import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { domainStore } from './domain';

function createGrid() {
	// grid 现在代理给 domainStore 的 initialGrid 属性
	const { subscribe } = derived(domainStore, $domain => $domain.initialGrid);

	return {
		subscribe,


		generate(difficulty) {
			const initGrid = generateSudoku(difficulty);

			domainStore.init(initGrid);
		},

		decodeSencode(sencode) {
			const initGrid = decodeSencode(sencode);
			domainStore.init(initGrid);
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();


function createUserGrid() {
	// userGrid 现在代理给 domainStore 的 grid 属性
	const { subscribe } = derived(domainStore, $domain => $domain.grid);

	return {
		subscribe,

		set: (pos, value) => {
			domainStore.guess(pos.y, pos.x, value);
		},

		applyHint: (pos) => {
			hints.useHint();
			let initialGrid;
			const unsubscribe = domainStore.subscribe(s => initialGrid = s.initialGrid);
			unsubscribe();

			const solvedSudoku = solveSudoku(initialGrid);
			const hintValue = solvedSudoku[pos.y][pos.x];
			domainStore.applyHint(pos.y, pos.x, hintValue);
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(domainStore, $domain => $domain.invalidCells);